setTimeout(() => {
  if (this.frm_cot_moneda == "COP"){
  const name = 'frm_valor_asegurado_cop_opcion_1';
  const input = document.querySelector(`input[name="${name}"]`);
  if (!input) return;
  const group = input.closest('.form-group');

  const minRaw = this.frm_valor_asegurado_minimo_cop;
  const maxRaw = this.frm_valor_asegurado_maximo_cop;

  const min = toNumber(minRaw);
  const max = toNumber(maxRaw);

  if (!isFinite(min) || !isFinite(max)) { clearFeedback(); return; }

  const lo = Math.min(min, max);
  const hi = Math.max(min, max);

  const raw = (this[name] ?? '').toString().trim();
  if (!raw) { clearFeedback(); return; }

  const val = toNumber(raw);

  // ✅ ACEPTAR 0 COMO VÁLIDO (caso especial)
  if (val === 0) {
    setValid();
    if (group) delete group.dataset.vaModalOpened;
    return; // <- salimos sin validar rango ni mostrar modal
  }

  // Validación de rango normal
  if (!isFinite(val) || val < lo || val > hi) {
    setInvalid(`El valor debe estar entre ${fmt(lo)} COP y ${fmt(hi)} COP`);
    if (!group?.dataset?.vaModalOpened) {
      if (group) group.dataset.vaModalOpened = '1';
    }
  } else {
    setValid();
    if (group) delete group.dataset.vaModalOpened;
  }

  function toNumber(x) {
    if (x === null || x === undefined) return NaN;
    let s = String(x).trim();
    if (!s) return NaN;

    // Normaliza "1.234,56" -> 1234.56 o "1,234.56" -> 1234.56
    const tieneComa = /,/.test(s);
    const tienePunto = /\./.test(s);
    if (tieneComa && (!tienePunto || s.lastIndexOf(',') > s.lastIndexOf('.'))) {
      s = s.replace(/\./g, '').replace(/,/g, '.');
    } else {
      s = s.replace(/(?<=\d)[, ](?=\d{3}\b)/g, '');
    }
    return parseFloat(s);
  }

  function setInvalid(message) {
    input.classList.remove('is-valid');
    if (!input.classList.contains('is-invalid')) input.classList.add('is-invalid');

    if (!group) return;
    let fb = group.querySelector('.invalid-feedback[data-source="va-range-1"]');
    if (!fb) {
      fb = document.createElement('div');
      fb.className = 'invalid-feedback d-block';
      fb.dataset.source = 'va-range-1';
      const help = group.querySelector('small.form-text');
      if (help) group.insertBefore(fb, help); else group.appendChild(fb);
    }
    fb.innerHTML = `<div>${message}</div>`;
  }

  function setValid() {
    input.classList.remove('is-invalid');
    //input.classList.add('is-valid');
    if (!group) return;
    const fb = group.querySelector('.invalid-feedback[data-source="va-range-1"]');
    if (fb) fb.remove();
  }

  function clearFeedback() {
    input.classList.remove('is-invalid', 'is-valid');
    if (!group) return;
    const fb = group.querySelector('.invalid-feedback[data-source="va-range-1"]');
    if (fb) fb.remove();
    if (group.dataset) delete group.dataset.vaModalOpened;
  }

  function fmt(n) {
    if (typeof n === 'number' && isFinite(n)) {
      try { return n.toLocaleString('es-EC'); } catch { return String(n); }
    }
    return String(n);
  }
  }
}, 180);


