  const camposPorMoneda = {
    COP: [
      'frm_valor_asegurado_cop_opcion_1',
      'frm_valor_asegurado_cop_opcion_2',
      'frm_valor_asegurado_cop_opcion_3',
    ],
    USD: [
      'frm_valor_asegurado_usd_opcion_1',
      'frm_valor_asegurado_usd_opcion_2',
      'frm_valor_asegurado_usd_opcion_3',
    ],
    EUR: [
      'frm_valor_asegurado_eur_opcion_1',
      'frm_valor_asegurado_eur_opcion_2',
      'frm_valor_asegurado_eur_opcion_3',
    ],
  };

  const campos = camposPorMoneda[moneda];
  if (!campos) return false; // Moneda no reconocida → no procede

  // Normaliza strings numéricos: permite $, espacios, puntos/comas y miles
  const aNumero = (str) => {
    if (str == null) return NaN;
    let s = String(str).trim();
    if (s === '') return NaN;
    // quita cualquier símbolo que no sea dígito, coma, punto o signo
    s = s.replace(/[^\d.,+-]/g, '');

    const lastDot = s.lastIndexOf('.');
    const lastComma = s.lastIndexOf(',');

    if (lastDot !== -1 && lastComma !== -1) {
      // ambos presentes: el último actúa como decimal
      const decimalEsComa = lastComma > lastDot;
      if (decimalEsComa) {
        s = s.replace(/\./g, ''); // . como miles
        s = s.replace(',', '.');  // , como decimal
      } else {
        s = s.replace(/,/g, '');  // , como miles
        // . ya como decimal
      }
    } else if (lastComma !== -1) {
      // solo coma → tratar como decimal
      s = s.replace(/\./g, '');
      s = s.replace(',', '.');
    } else {
      // solo punto → ya es decimal; eliminar comas de miles si hubiera
      s = s.replace(/,/g, '');
    }

    return Number(s);
  };

  const esValido = (valor) => {
    if (valor == null) return false;
    if (String(valor).trim() === '') return false;
    const n = aNumero(valor);
    if (Number.isNaN(n)) return false;
    return n !== 0; // distinto de 0 (positivo o negativo cuenta como válido)
  };

  // Procede si al menos UNA de las 3 opciones de la moneda seleccionada es válida
  return campos.some((campo) => esValido(this[campo]));

